import { browser } from '$app/environment';
import { getContext } from 'svelte';
let included_icons;
if (browser) {
    included_icons = new Set();
    if (import.meta.hot) {
        import.meta.hot.on('vite:beforeUpdate', () => {
            included_icons.clear();
        });
    }
}
const ICON_SET = Symbol();
export function get_included_icons() {
    if (browser)
        return included_icons;
    const context = getContext('__svelte__');
    if (!context)
        throw new Error('SvelteKit global context not found');
    if (!context[ICON_SET])
        context[ICON_SET] = new Set();
    return context[ICON_SET];
}
/** include_icon - Abbreviated to `i` because it's copied over thousands of components */
export function i(icon) {
    const included_icons = get_included_icons();
    if (included_icons.has(icon))
        return false;
    included_icons.add(icon);
    return true;
}
/** noremove - Abbreviated to `n` because it's copied over thousands of components */
// We can never remove the svg instances from the dom because they won't be re-added if the
// icon remounts
export const n = function (node) {
    return {
        destroy() {
            document.body.appendChild(node);
        }
    };
};
/** get_style - Abbreviated to `s` because it's copied over thousands of components */
export function s(size, style_) {
    if (size === undefined && !style_)
        return undefined;
    const styles = [];
    if (size !== undefined)
        styles.push(`--🟃s:${size}px`);
    if (style_)
        styles.push(style_);
    return styles.join(';');
}
